refentry.refsect1:
&reftitle.description;
public static intYar_Concurrent_Client::call stringuri stringmethod arrayparameters callablecallback callableerror_callback arrayoptions
Registra uma chamada RPC, mas não a envia imediatamente, ela será enviada durante uma nova chamada a Yar_Concurrent_Client::loop.

  &reftitle.examples;



<?php

function callback($retval, $callinfo)
{
    var_dump($retval);
}

function error_callback($type, $error, $callinfo)
{
    error_log($error);
}

Yar_Concurrent_Client::call("http://host/api/", "some_method", array("parameters"), "callback");

// se a função de retorno não for especificada, a função de retorno no loop será usada
Yar_Concurrent_Client::call("http://host/api/", "some_method", array("parameters"));

// este servidor aceita empacotador json
Yar_Concurrent_Client::call("http://host/api/", "some_method", array("parameters"), "callback", NULL, array(YAR_OPT_PACKAGER => "json"));

// tempo limite personalizado
Yar_Concurrent_Client::call("http://host/api/", "some_method", array("parameters"), "callback", NULL, array(YAR_OPT_TIMEOUT => 1));

// As solicitações ainda não foram enviadas


   &example.outputs.similar;
